+fn build_rollup_refresh_scan_query(
+    strata: impl Iterator<Item = TouchedStratum>,
+) -> (String, Vec<Value>) {
+    let mut sql = String::from(ROLLUP_REFRESH_SELECT_PREFIX_SQL);
